import{mekongStore}from '../services/mekong-store.js';import{Logger}from '../shared/logger.js';const AdminClient={config:{baseUrl: '/functions/v1/admin',timeout: 30000,debug: false},init(){this.setupEventListeners();},setupEventListeners(){document.addEventListener('mekong:data-refresh',async(e)=>{const{entity}=e.detail;if(entity){await this.refreshEntity(entity);}});},async fetch(entity,options={}){const url=`${this.config.baseUrl}/${entity}`;try{const response=await fetch(url,{method: 'GET',headers:{'Content-Type': 'application/json',},signal: AbortSignal.timeout(this.config.timeout)});if(!response.ok){throw new Error(`HTTP ${response.status}: ${response.statusText}`);}const data=await response.json();mekongStore.set(entity,data);return data;}catch(error){Logger.error(`[AdminClient] Failed to fetch ${entity}:`,error);throw error;}},async create(entity,data){const url=`${this.config.baseUrl}/${entity}`;try{const response=await fetch(url,{method: 'POST',headers:{'Content-Type': 'application/json',},body: JSON.stringify(data),signal: AbortSignal.timeout(this.config.timeout)});if(!response.ok){throw new Error(`HTTP ${response.status}: ${response.statusText}`);}const result=await response.json();await this.refreshEntity(entity);return result;}catch(error){Logger.error(`[AdminClient] Failed to create ${entity}:`,error);throw error;}},async update(entity,id,data){const url=`${this.config.baseUrl}/${entity}/${id}`;try{const response=await fetch(url,{method: 'PUT',headers:{'Content-Type': 'application/json',},body: JSON.stringify(data),signal: AbortSignal.timeout(this.config.timeout)});if(!response.ok){throw new Error(`HTTP ${response.status}: ${response.statusText}`);}const result=await response.json();await this.refreshEntity(entity);return result;}catch(error){Logger.error(`[AdminClient] Failed to update ${entity}:`,error);throw error;}},async delete(entity,id){const url=`${this.config.baseUrl}/${entity}/${id}`;try{const response=await fetch(url,{method: 'DELETE',signal: AbortSignal.timeout(this.config.timeout)});if(!response.ok){throw new Error(`HTTP ${response.status}: ${response.statusText}`);}await this.refreshEntity(entity);}catch(error){Logger.error(`[AdminClient] Failed to delete ${entity}:`,error);throw error;}},async refreshEntity(entity){try{await this.fetch(entity);}catch(error){Logger.error(`[AdminClient] Failed to refresh ${entity}:`,error);}},async getclients(){return this.fetch('clients');},async getCampaigns(){return this.fetch('campaigns');},async getLeads(){return this.fetch('leads');},async getDeals(){return this.fetch('deals');}};if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>AdminClient.init());}else{AdminClient.init();}export{AdminClient};export default AdminClient;